  ?book wdt:P31/wdt:P279* wd:Q571 .
  ?book p:P166 ?awardStatement .
  ?awardStatement ps:P166 wd:Q10336568 ;
                  pq:P585 ?date .
  FILTER(YEAR(?date) = 2019)
